import { ServiceOption } from './types';

export const SERVICE_OPTIONS: ServiceOption[] = [
  { id: 'soc', name: 'Start of Care (SOC)', defaultRate: 150.00 },
  { id: 'recert', name: 'Recertification', defaultRate: 125.00 },
  { id: 'roc', name: 'Resumption of Care (ROC)', defaultRate: 130.00 },
  { id: 'sn', name: 'Skilled Nursing Visit', defaultRate: 85.00 },
  { id: 'dc', name: 'Discharge', defaultRate: 100.00 },
  { id: 'iv', name: 'IV Service', defaultRate: 110.00 },
  { id: 'eval', name: 'Evaluation', defaultRate: 95.00 },
  { id: 'wound', name: 'Wound Care', defaultRate: 90.00 },
  { id: 'meds', name: 'Medication Management', defaultRate: 65.00 },
  { id: 'teach', name: 'Patient Teaching/Training', defaultRate: 75.00 },
  { id: 'supervision', name: 'HHA Supervision', defaultRate: 60.00 },
  { id: 'other', name: 'Other', defaultRate: 0.00 },
];

export const PROVIDER_INFO = {
  name: "Arpi Moradi, RN",
  title: "Registered Nurse",
  address: "5239 Harter Lane\nLa Canada, CA 91101",
  phone: "818-515-8980",
  email: "amoradi2310@gmail.com"
};

export const DEFAULT_TERMS = "Make Check Payable to Bloom Drip Co";

import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Calendar, User, MapPin, Hash, DollarSign, Mail, RotateCcw, Sparkles, Wand2, Loader2, AlertTriangle, Save, Users, Settings, Clock, History, Printer, FileDown, FileText, FilePlus, FileCheck } from 'lucide-react';
import { ProviderHeader } from './components/ProviderHeader';
import { InvoiceControls } from './components/InvoiceControls';
import { MagicAddModal } from './components/MagicAddModal';
import { CustomerManagerModal } from './components/CustomerManagerModal';
import { InvoiceHistoryModal } from './components/InvoiceHistoryModal';
import { polishText, parseInvoiceItems, generateInvoiceImage } from './ai-service';
import { InvoiceData, InvoiceItem, Customer, SavedInvoice, InvoiceStatus, DEFAULT_MILEAGE_RATE } from './types';
import { SERVICE_OPTIONS, DEFAULT_TERMS, PROVIDER_INFO } from './constants';

// Declare globals loaded via CDN
declare var html2pdf: any;
declare var html2canvas: any;

const App: React.FC = () => {
  // --- State Initialization ---
  const [data, setData] = useState<InvoiceData>(() => {
    // Try to load from local storage to prevent data loss on refresh
    const saved = localStorage.getItem('invoiceData');
    if (saved) {
      const parsed = JSON.parse(saved);
      // Auto-update legacy payment terms if they match the old default
      if (parsed.paymentTerms && (parsed.paymentTerms.includes("Please make checks payable") || parsed.paymentTerms.includes("Arpi Moradi"))) {
        parsed.paymentTerms = DEFAULT_TERMS;
      }
      return parsed;
    }

    // Default state with starting invoice number 2310
    return {
      invoiceNumber: '2310',
      date: new Date().toISOString().split('T')[0],
      dueDate: new Date(Date.now() + 14 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
      billToName: '',
      billToAddress: '',
      billToPhone: '',
      billToEmail: '',
      mileageRate: DEFAULT_MILEAGE_RATE,
      items: [
        {
          id: crypto.randomUUID(),
          date: new Date().toISOString().split('T')[0],
          patientName: '',
          serviceName: SERVICE_OPTIONS[0].name,
          description: '',
          quantity: 1,
          rate: SERVICE_OPTIONS[0].defaultRate,
          miles: 0,
        }
      ],
      notes: '',
      paymentTerms: DEFAULT_TERMS
    };
  });

  // Customer Database State
  const [savedCustomers, setSavedCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('savedCustomers');
    return saved ? JSON.parse(saved) : [];
  });

  // Invoice History State
  const [invoiceHistory, setInvoiceHistory] = useState<SavedInvoice[]>(() => {
    const saved = localStorage.getItem('invoiceHistory');
    return saved ? JSON.parse(saved) : [];
  });

  const [isMagicModalOpen, setIsMagicModalOpen] = useState(false);
  const [isCustomerManagerOpen, setIsCustomerManagerOpen] = useState(false);
  const [isHistoryModalOpen, setIsHistoryModalOpen] = useState(false);
  const [isPolishingNotes, setIsPolishingNotes] = useState(false);
  const [isDownloadOptionsOpen, setIsDownloadOptionsOpen] = useState(false);

  // --- Derived State ---
  const matchingCustomer = data.billToName 
    ? savedCustomers.find(c => c.name.trim().toLowerCase() === data.billToName.trim().toLowerCase()) 
    : null;

  // --- Effects ---
  useEffect(() => {
    localStorage.setItem('invoiceData', JSON.stringify(data));
  }, [data]);

  useEffect(() => {
    localStorage.setItem('savedCustomers', JSON.stringify(savedCustomers));
  }, [savedCustomers]);

  useEffect(() => {
    localStorage.setItem('invoiceHistory', JSON.stringify(invoiceHistory));
  }, [invoiceHistory]);

  // --- Calculations ---
  const subtotal = data.items.reduce((sum, item) => sum + (item.quantity * item.rate), 0);
  const totalMiles = data.items.reduce((sum, item) => sum + item.miles, 0);
  const mileageTotal = totalMiles * data.mileageRate;
  const grandTotal = subtotal + mileageTotal;

  // Format date for display
  const formattedDueDate = new Date(data.dueDate).toLocaleDateString('en-US', { 
    month: 'long', 
    day: 'numeric', 
    year: 'numeric' 
  });

  // --- Handlers ---
  const updateField = (field: keyof InvoiceData, value: any) => {
    setData(prev => ({ ...prev, [field]: value }));
  };

  const addItem = () => {
    setData(prev => ({
      ...prev,
      items: [
        ...prev.items,
        {
          id: crypto.randomUUID(),
          date: prev.date, // Default to invoice date
          patientName: '',
          serviceName: SERVICE_OPTIONS[0].name,
          description: '',
          quantity: 1,
          rate: SERVICE_OPTIONS[0].defaultRate,
          miles: 0,
        }
      ]
    }));
  };

  const handleNewInvoice = () => {
    if (confirm("Create a new invoice? Any unsaved changes on the current form will be lost.")) {
      // Logic to find the next invoice number
      let nextNum = 2310;

      // Check history for highest number
      if (invoiceHistory.length > 0) {
        const numbers = invoiceHistory
          .map(inv => parseInt(inv.invoiceNumber))
          .filter(n => !isNaN(n));

        if (numbers.length > 0) {
          nextNum = Math.max(...numbers) + 1;
        }
      }

      // Also check current data if it's higher
      const currentNum = parseInt(data.invoiceNumber);
      if (!isNaN(currentNum) && currentNum >= nextNum) {
        nextNum = currentNum + 1;
      }

      setData({
        invoiceNumber: nextNum.toString(),
        date: new Date().toISOString().split('T')[0],
        dueDate: new Date(Date.now() + 14 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
        billToName: '',
        billToAddress: '',
        billToPhone: '',
        billToEmail: '',
        mileageRate: DEFAULT_MILEAGE_RATE,
        items: [
          {
            id: crypto.randomUUID(),
            date: new Date().toISOString().split('T')[0],
            patientName: '',
            serviceName: SERVICE_OPTIONS[0].name,
            description: '',
            quantity: 1,
            rate: SERVICE_OPTIONS[0].defaultRate,
            miles: 0,
          }
        ],
        notes: '',
        paymentTerms: DEFAULT_TERMS
      });
    }
  };

  const handleMagicAddItems = (newItems: any[]) => {
    const formattedItems: InvoiceItem[] = newItems.map(item => {
      // Find matching service to set default rate
      const matchedService = SERVICE_OPTIONS.find(s => 
        s.name.toLowerCase() === item.serviceName?.toLowerCase() || 
        (item.serviceName && s.name.toLowerCase().includes(item.serviceName.toLowerCase()))
      );

      return {
        id: crypto.randomUUID(),
        date: item.date || data.date,
        patientName: item.patientName || '',
        serviceName: matchedService ? matchedService.name : (item.serviceName || SERVICE_OPTIONS[0].name),
        description: item.description || '',
        quantity: item.quantity || 1,
        rate: matchedService ? matchedService.defaultRate : 0,
        miles: item.miles || 0
      };
    });

    setData(prev => ({
      ...prev,
      items: [...prev.items, ...formattedItems]
    }));
  };

  const handlePolishNotes = async () => {
    if (!data.notes.trim()) return;
    setIsPolishingNotes(true);
    try {
      const polished = await polishText(data.notes);
      updateField('notes', polished);
    } catch (error) {
      console.error("Failed to polish notes", error);
      alert("AI Service is temporarily unavailable. Please try again.");
    } finally {
      setIsPolishingNotes(false);
    }
  };

  const updateItem = (id: string, field: keyof InvoiceItem, value: any) => {
    setData(prev => ({
      ...prev,
      items: prev.items.map(item => {
        if (item.id !== id) return item;

        // If changing service name, auto-update rate if it matches a preset
        if (field === 'serviceName') {
          const service = SERVICE_OPTIONS.find(s => s.name === value);
          if (service) {
            return { ...item, [field]: value, rate: service.defaultRate };
          }
        }
        return { ...item, [field]: value };
      })
    }));
  };

  const removeItem = (id: string) => {
    if (data.items.length === 1) return; // Prevent deleting last row
    setData(prev => ({
      ...prev,
      items: prev.items.filter(item => item.id !== id)
    }));
  };

  // --- Customer Database Handlers ---
  const handleSaveCustomer = () => {
    if (!data.billToName) {
      alert("Please enter a Company/Agency Name first.");
      return;
    }

    const newCustomer: Customer = {
      id: crypto.randomUUID(),
      name: data.billToName,
      address: data.billToAddress,
      phone: data.billToPhone,
      email: data.billToEmail
    };

    // Check if duplicate name exists, if so update it
    const existingIndex = savedCustomers.findIndex(c => c.name.toLowerCase() === newCustomer.name.toLowerCase());

    if (existingIndex >= 0) {
      if (confirm(`Update existing client "${newCustomer.name}"?`)) {
        const updated = [...savedCustomers];
        updated[existingIndex] = newCustomer;
        setSavedCustomers(updated);
      }
    } else {
      setSavedCustomers(prev => [...prev, newCustomer]);
    }
  };

  const handleLoadCustomer = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const customerId = e.target.value;
    if (!customerId) return;

    const customer = savedCustomers.find(c => c.id === customerId);
    if (customer) {
      setData(prev => ({
        ...prev,
        billToName: customer.name,
        billToAddress: customer.address,
        billToPhone: customer.phone,
        billToEmail: customer.email
      }));
    }
  };

  const handleUpdateCustomer = (updatedCustomer: Customer) => {
    setSavedCustomers(prev => prev.map(c => c.id === updatedCustomer.id ? updatedCustomer : c));
  };

  const handleDeleteCustomer = (id: string) => {
    setSavedCustomers(prev => prev.filter(c => c.id !== id));
  };

  // --- Invoice History Handlers ---
  const handleSaveToHistory = () => {
    const newRecord: SavedInvoice = {
      ...data,
      id: crypto.randomUUID(),
      savedAt: new Date().toISOString(),
      status: 'pending',
      totalAmount: grandTotal
    };

    // Check if invoice # already exists
    const existingIndex = invoiceHistory.findIndex(i => i.invoiceNumber === data.invoiceNumber);
    if (existingIndex >= 0) {
      if (confirm(`Invoice #${data.invoiceNumber} already exists in history. Overwrite it?`)) {
        const updated = [...invoiceHistory];
        // Preserve status if we are just updating details
        newRecord.status = updated[existingIndex].status; 
        updated[existingIndex] = newRecord;
        setInvoiceHistory(updated);
        alert(`Invoice #${data.invoiceNumber} updated in history.`);
      }
    } else {
      setInvoiceHistory(prev => [newRecord, ...prev]);
      alert(`Invoice #${data.invoiceNumber} saved to history.`);
    }
  };

  const handleLoadHistory = (invoice: SavedInvoice) => {
    if (confirm("Load this invoice? Unsaved changes to the current form will be lost.")) {
      const { id, savedAt, status, totalAmount, ...loadedData } = invoice;
      setData(loadedData);
      setIsHistoryModalOpen(false);
    }
  };

  const handleInvoiceStatusChange = (id: string, newStatus: InvoiceStatus) => {
    setInvoiceHistory(prev => prev.map(inv => {
      if (inv.id === id) {
        return { ...inv, status: newStatus };
      }
      return inv;
    }));
  };

  const handleDeleteFromHistory = (id: string) => {
    if (confirm("Are you sure you want to delete this invoice from history?")) {
      setInvoiceHistory(prev => prev.filter(inv => inv.id !== id));
    }
  };

  const handleDownloadPDF = () => {
    setIsDownloadOptionsOpen(false);
    const element = document.getElementById('invoice-container');
    if (!element) return;

    const opt = {
      margin: [0.5, 0.5],
      filename: `Invoice_${data.invoiceNumber || 'Draft'}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true, logging: false },
      jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' }
    };

    html2pdf().set(opt).from(element).save();
  };

  const handleDownloadWord = () => {
    setIsDownloadOptionsOpen(false);

    // Construct HTML content optimized for Word with Professional Styling
    const content = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head>
        <meta charset="utf-8">
        <title>Invoice ${data.invoiceNumber}</title>
        <style>
          body { font-family: 'Calibri', 'Segoe UI', sans-serif; font-size: 11pt; color: #333333; }

          /* Layout Tables */
          table.layout { width: 100%; border-collapse: collapse; border: none; margin-bottom: 20px; }
          table.layout td { border: none; padding: 0; vertical-align: top; }

          /* Header */
          .header-name { font-size: 36pt; color: #1e3a8a; font-weight: bold; font-family: 'Times New Roman', serif; line-height: 1; }
          .header-rn { font-size: 14pt; color: #e11d48; font-weight: bold; letter-spacing: 2px; margin-top: 5px; text-transform: uppercase; }
          .header-line { border-bottom: 4px solid #dbeafe; margin-bottom: 20px; padding-bottom: 10px; }

          .contact-box { 
            text-align: right; 
            font-size: 11pt; 
            color: #475569;
            border-left: 4px solid #1e3a8a;
            padding-left: 15px;
            margin-left: auto;
            display: inline-block;
          }

          /* Titles */
          .section-title { font-size: 10pt; color: #4f46e5; font-weight: bold; text-transform: uppercase; letter-spacing: 1px; margin-bottom: 5px; }
          .invoice-title { font-size: 40pt; color: #1e3a8a; font-weight: 900; text-transform: uppercase; line-height: 1; margin: 0; }

          /* Data Table */
          table.data-table { width: 100%; border-collapse: collapse; border: 1px solid #e2e8f0; margin-top: 10px; }
          table.data-table th { 
            background-color: #1e3a8a; 
            color: #ffffff; 
            padding: 10px; 
            text-align: left; 
            font-size: 10pt; 
            font-weight: bold; 
            text-transform: uppercase;
            border: 1px solid #1e3a8a;
          }
          table.data-table td { 
            padding: 10px; 
            border: 1px solid #e2e8f0; 
            font-size: 10pt; 
            vertical-align: top;
          }
          table.data-table tr:nth-child(even) { background-color: #f8fafc; }

          /* Footer/Totals */
          .notes-box { background-color: #f1f5f9; border-left: 4px solid #cbd5e1; padding: 10px; font-size: 10pt; margin-top: 10px; }
          .payment-box { margin-top: 15px; font-size: 12pt; font-weight: bold; color: #1e3a8a; }
          .payment-date { color: #e11d48; font-size: 11pt; margin-top: 5px; }

          table.totals { width: 100%; border-collapse: collapse; margin-top: 10px; }
          table.totals td { padding: 5px 0; font-size: 11pt; text-align: right; }
          .total-label { font-weight: bold; color: #64748b; }
          .total-value { font-weight: bold; color: #1e293b; padding-left: 20px; }
          .grand-total-row td { padding-top: 10px; padding-bottom: 10px; border-top: 2px solid #1e3a8a; border-bottom: 2px solid #1e3a8a; }
          .grand-total-label { font-size: 16pt; font-weight: bold; color: #1e3a8a; text-transform: uppercase; }
          .grand-total-value { font-size: 24pt; font-weight: bold; color: #e11d48; }

        </style>
      </head>
      <body>

        <!-- Header Section -->
        <div class="header-line">
            <table class="layout">
            <tr>
                <td width="60%">
                <div class="header-name">Arpi Moradi</div>
                <div class="header-rn">RN | REGISTERED NURSE</div>
                </td>
                <td width="40%" align="right">
                <div class="contact-box">
                    <strong>${PROVIDER_INFO.address.replace(/\n/g, '<br>')}</strong><br>
                    <span style="color: #1e40af;">📞 ${PROVIDER_INFO.phone}</span><br>
                    <span style="color: #1e40af;">📧 ${PROVIDER_INFO.email}</span>
                </div>
                </td>
            </tr>
            </table>
        </div>

        <!-- Bill To & Meta -->
        <table class="layout" style="margin-bottom: 30px;">
          <tr>
            <td width="55%">
              <div class="section-title">Bill To</div>
              <div style="font-size: 14pt; font-weight: bold; color: #1e293b; margin-bottom: 5px;">${data.billToName || '__________________'}</div>
              <div style="font-size: 11pt; color: #475569; line-height: 1.4;">
                ${data.billToAddress.replace(/\n/g, '<br>') || ''}<br>
                ${data.billToPhone ? 'Phone: ' + data.billToPhone + '<br>' : ''}
                ${data.billToEmail ? 'Email: ' + data.billToEmail : ''}
              </div>
            </td>
            <td width="45%" align="right" valign="top">
              <div class="invoice-title">INVOICE</div>
              <table style="float: right; margin-top: 10px;">
                <tr>
                    <td style="color: #64748b; font-weight: bold; padding-right: 15px;">Invoice #</td>
                    <td style="font-weight: bold; font-size: 12pt;">${data.invoiceNumber}</td>
                </tr>
                <tr>
                    <td style="color: #64748b; font-weight: bold; padding-right: 15px;">Date</td>
                    <td style="font-weight: bold; font-size: 12pt;">${data.date}</td>
                </tr>
                <tr>
                    <td style="color: #64748b; font-weight: bold; padding-right: 15px;">Due Date</td>
                    <td style="font-weight: bold; font-size: 12pt; color: #e11d48;">${data.dueDate}</td>
                </tr>
              </table>
            </td>
          </tr>
        </table>

        <!-- Items Table -->
        <table class="data-table">
          <thead>
            <tr>
              <th width="15%">Date</th>
              <th width="20%">Patient</th>
              <th width="30%">Service / Description</th>
              <th width="8%" align="center">Miles</th>
              <th width="7%" align="center">Qty</th>
              <th width="10%" align="right">Rate</th>
              <th width="10%" align="right">Amount</th>
            </tr>
          </thead>
          <tbody>
            ${data.items.map(item => `
              <tr>
                <td>${item.date}</td>
                <td><strong>${item.patientName}</strong></td>
                <td>
                  <strong style="color: #1e3a8a;">${item.serviceName}</strong><br>
                  <span style="font-size: 9pt; color: #64748b; font-style: italic;">${item.description}</span>
                </td>
                <td align="center">${item.miles || '-'}</td>
                <td align="center">${item.quantity}</td>
                <td align="right">$${item.rate.toFixed(2)}</td>
                <td align="right"><strong>$${(item.quantity * item.rate).toFixed(2)}</strong></td>
              </tr>
            `).join('')}
          </tbody>
        </table>

        <!-- Footer Grid -->
        <table class="layout" style="margin-top: 30px;">
          <tr>
            <td width="60%" style="padding-right: 30px;">
                <div class="section-title">Notes</div>
                <div class="notes-box">
                    ${data.notes ? data.notes.replace(/\n/g, '<br>') : 'No additional notes.'}
                </div>

                <div class="payment-box">
                    ${data.paymentTerms}
                </div>
                <div class="payment-date">
                    Payment due by ${formattedDueDate}
                </div>
            </td>
            <td width="40%" valign="top">
                <table class="totals">
                    <tr>
                        <td class="total-label">Service Subtotal:</td>
                        <td class="total-value">$${subtotal.toFixed(2)}</td>
                    </tr>
                    <tr>
                        <td class="total-label">Mileage (${totalMiles} mi x $${data.mileageRate}):</td>
                        <td class="total-value">$${mileageTotal.toFixed(2)}</td>
                    </tr>
                    <tr class="grand-total-row">
                        <td class="grand-total-label">Total</td>
                        <td class="grand-total-value">$${grandTotal.toFixed(2)}</td>
                    </tr>
                </table>
            </td>
          </tr>
        </table>

      </body>
      </html>
    `;

    const blob = new Blob(['\ufeff', content], {
      type: 'application/msword'
    });

    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Invoice_${data.invoiceNumber || 'Draft'}.doc`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="min-h-screen bg-slate-200 text-slate-800 print:bg-white pb-20 md:pb-0">
      <MagicAddModal 
        isOpen={isMagicModalOpen} 
        onClose={() => setIsMagicModalOpen(false)}
        onAddItems={handleMagicAddItems}
        defaultDate={data.date}
      />

      <CustomerManagerModal 
        isOpen={isCustomerManagerOpen}
        onClose={() => setIsCustomerManagerOpen(false)}
        customers={savedCustomers}
        onUpdateCustomer={handleUpdateCustomer}
        onDeleteCustomer={handleDeleteCustomer}
      />

      <InvoiceHistoryModal
        isOpen={isHistoryModalOpen}
        onClose={() => setIsHistoryModalOpen(false)}
        history={invoiceHistory}
        onLoad={handleLoadHistory}
        onToggleStatus={handleInvoiceStatusChange}
        onDelete={handleDeleteFromHistory}
      />

      {/* Download Options Modal */}
      {isDownloadOptionsOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[80] flex items-center justify-center p-4 print:hidden">
          <div className="bg-white rounded-xl shadow-2xl max-w-sm w-full p-6 animate-in fade-in zoom-in duration-200">
            <h3 className="text-xl font-bold text-slate-900 mb-4 flex items-center gap-2">
              <Printer className="text-blue-900" size={24} />
              Download Options
            </h3>

            <div className="space-y-3">
              {/* Option 1: PDF */}
              <button
                onClick={handleDownloadPDF}
                className="w-full flex items-center justify-between p-4 bg-rose-50 border border-rose-100 rounded-lg hover:bg-rose-100 transition-colors group"
              >
                <div className="text-left">
                  <span className="block font-bold text-rose-900 text-lg">Download PDF</span>
                  <span className="block text-sm text-rose-700">Best for printing & sharing</span>
                </div>
                <FileCheck size={24} className="text-rose-600 group-hover:scale-110 transition-transform" />
              </button>

              {/* Option 2: Word Doc */}
              <button
                onClick={handleDownloadWord}
                className="w-full flex items-center justify-between p-4 bg-blue-50 border border-blue-100 rounded-lg hover:bg-blue-100 transition-colors group"
              >
                <div className="text-left">
                  <span className="block font-bold text-blue-900 text-lg">Download Word (DOC)</span>
                  <span className="block text-sm text-blue-700">Editable document</span>
                </div>
                <FileText size={24} className="text-blue-600 group-hover:scale-110 transition-transform" />
              </button>
            </div>

            <button
              onClick={() => setIsDownloadOptionsOpen(false)}
              className="mt-6 w-full py-3 text-slate-500 font-bold hover:bg-slate-100 rounded-lg transition-colors"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      <InvoiceControls 
        onSaveToHistory={handleSaveToHistory}
        onDownload={() => setIsDownloadOptionsOpen(true)}
        hasEmail={!!data.billToEmail}
      />

